CREATE TABLE IF NOT EXISTS `impressions` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `content_type` enum('post','page','service') NOT NULL,
  `content_id` int(10) unsigned NOT NULL,
  `viewer_ip` varchar(45) NOT NULL,
  `impression_at` datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_impressions_content_time` (`content_type`,`content_id`,`impression_at`),
  KEY `idx_impressions_ip_content_time` (`viewer_ip`,`content_type`,`content_id`,`impression_at`)
) ENGINE=InnoDB AUTO_INCREMENT=573 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

